-- ----------------------------
-- Table structure for activity
-- ----------------------------
DROP TABLE IF EXISTS `activity`;
CREATE TABLE `activity` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `uid` int(11) NOT NULL,
  `cover_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '封面图片地址',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '活动标题',
  `activity_time` timestamp NULL DEFAULT NULL COMMENT '活动时间',
  `apply_end_time` timestamp NULL DEFAULT NULL COMMENT '报名截止时间',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '内容',
  `type` tinyint(2) DEFAULT '1' COMMENT '活动类型：1：活动 2：会务',
  `shelves_status` tinyint(2) DEFAULT '1' COMMENT '上下架：1：正常 2：已结束 （默认正常）',
  `status` tinyint(2) DEFAULT '1' COMMENT '状态 1.正常 2.审核中 3. 未通过 99.删除',
  `longitude` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '经度',
  `latitude` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '纬度',
  `address_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '地址全名',
  `address_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '地址简称',
  `visits` int(10) DEFAULT '0' COMMENT '访问数',
  `images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '活动图片',
  `recommend` tinyint(2) DEFAULT '2' COMMENT '推荐 1：推荐 2：不推荐 (默认2)',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=82 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='活动表';

-- ----------------------------
-- Records of activity
-- ----------------------------

-- ----------------------------
-- Table structure for activity_apply
-- ----------------------------
DROP TABLE IF EXISTS `activity_apply`;
CREATE TABLE `activity_apply` (
  `id` int(10) NOT NULL AUTO_INCREMENT,
  `uid` int(10) NOT NULL,
  `aid` int(10) NOT NULL COMMENT '活动id',
  `sid` int(10) NOT NULL COMMENT '规格id',
  `name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '联系人',
  `phone` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '联系电话',
  `company_name` varchar(255) DEFAULT NULL COMMENT '工作单位',
  `price` decimal(10,2) DEFAULT NULL COMMENT '价格',
  `order_no` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '订单编号',
  `payment_no` varchar(200) DEFAULT NULL COMMENT '支付订单号',
  `pay_type` tinyint(2) DEFAULT NULL COMMENT '支付方式 1: 微信 2：余额',
  `pay_status` tinyint(2) DEFAULT '3' COMMENT '支付状态 1: 不需要支付(免费)  2：已支付 3 : 未支付（默认） 4：支付超时',
  `refund_status` tinyint(2) DEFAULT '2' COMMENT '退款状态：1.不可退款  2.可退款 (默认)；3.退款成功；4.退款失败；5.退款中',
  `refund_at` timestamp NULL DEFAULT NULL COMMENT '退款时间',
  `status` tinyint(2) DEFAULT '2' COMMENT '报名状态 1：报名成功 2：未完成报名（默认）3:取消报名 (退款)99: 删除',
  `paid_at` timestamp NULL DEFAULT NULL COMMENT '支付时间',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=73 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='活动报名表';

