  `aid` int(10) unsigned DEFAULT NULL COMMENT '活动id',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '名称',
  `stint` int(10) unsigned NOT NULL COMMENT '限制人数',
  `remainder` int(10) DEFAULT NULL COMMENT '剩余人数',
  `price` decimal(10,2) DEFAULT NULL COMMENT '价格',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
