  `type` tinyint(10) DEFAULT '1' COMMENT '分类id',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '详细内容',
  `images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '供需图片',
  `visits` int(10) DEFAULT '0' COMMENT '访问数',
  `likes` int(10) DEFAULT '0' COMMENT '点赞数',
  `status` tinyint(2) DEFAULT '1' COMMENT '状态 1.正常 2.审核中 3. 未通过 99.删除',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=MyISAM AUTO_INCREMENT=157 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='供需表';

-- ----------------------------
-- Records of supply_demand
-- ----------------------------

-- ----------------------------
-- Table structure for tag
-- ----------------------------
DROP TABLE IF EXISTS `tag`;
CREATE TABLE `tag` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `uid` int(10) DEFAULT NULL COMMENT '用户id',
  `other_uid` int(10) DEFAULT NULL COMMENT '对方id （type=2,个人记录其它人名片标签可用）',
  `info_id` int(10) DEFAULT NULL COMMENT '信息id',
  `type` tinyint(2) NOT NULL DEFAULT '1' COMMENT '类别 ： 1.个人名片标签  2.个人记录别人名片更新（未完待续）',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '标签内容',
  `status` tinyint(2) DEFAULT '1' COMMENT '状态： 1.正常 99.删除',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=MyISAM AUTO_INCREMENT=163 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='标签表';

