-- ----------------------------

-- ----------------------------
-- Table structure for user_collection
-- ----------------------------
DROP TABLE IF EXISTS `user_collection`;
CREATE TABLE `user_collection` (
  `id` int(10) NOT NULL AUTO_INCREMENT,
  `uid` int(10) DEFAULT NULL COMMENT '用户id',
  `info_id` int(10) DEFAULT NULL COMMENT '信息id(type=1时表示来源用户)',
  `gid` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '群组id, 当type=1时可用(一个人可同时存在多个组)',
  `type` tinyint(2) DEFAULT NULL COMMENT '收藏类型：1,名片；2，供需； 3，活动',
  `status` tinyint(2) DEFAULT '1' COMMENT '状态：1.已收藏；2.已取消',
  `initial` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '来源用户真实姓名首字母',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=71 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='用户收藏表';

