INSERT INTO `communals` VALUES ('122', '关于将企业变更为内资企业公告', '<p>根据中国证券监督管理委员会证监许可[2013]1479号《关于发行股份购买资产并募集配套资金的批复》核准，非公发行股份购买资产并募集配套资金暨重大资产重组实完成后，公司股份总数变更为225,825,711股。伊泽瑞尔专营集团30,651,800股，占公司总股本的13.57%。</p><p><br/></p><p>2014年5月21日—2014年9月10日，通过竞价交易及大宗交易方式累计减持8,068,940股，减持后拉克丝专营集团持有公司22,582,860股，占公司总股本的10.00%。<br/></p><p><br/></p>', '2019-05-30 14:38:19', '2019-05-30 14:38:19', 'images/6f9ee0d9207f66fe4697ef2adbaee21e.png');
